from dataclasses import dataclass, field
from typing import Optional

@dataclass
class FlagContext:
    """Evaluation context passed to every flag check."""
    user_key: str
    session_id: str
    environment: str               # dev | staging | production
    tenant_id: Optional[str] = None
    region: str = "us-east-1"
    custom: dict = field(default_factory=dict)

    def to_ld_context(self) -> dict:
        """Convert to LaunchDarkly multi-context format."""
        ctx = {
            "kind": "multi",
            "user": {
                "key": self.user_key,
                "custom": {"tenant": self.tenant_id, "region": self.region},
            },
            "session": {
                "key": self.session_id,
                "custom": {"environment": self.environment},
            },
        }
        if self.custom:
            ctx["request"] = {"key": self.session_id, "custom": self.custom}
        return ctx

# Example usage
ctx = FlagContext(
    user_key="usr-123",
    session_id="sess-abc",
    environment="production",
    tenant_id="acme-corp",
    custom={"agent_type": "document-qa"},
)
variation = ld_client.variation("agent-v2-tool-calling", ctx.to_ld_context(), False)

import pytest
from unittest.mock import patch, MagicMock
from capability_router import CapabilityRouter, FlagContext

class FakeFlagClient:
    def __init__(self, overrides: dict):
        self._overrides = overrides

    def variation(self, key: str, context, default):
        return self._overrides.get(key, default)

@pytest.mark.parametrize("flag_value,expected_model", [
    (False, "gpt-4o-2024-05-13"),
    (True,  "gpt-4o-2024-08-06"),
])
def test_capability_routing(flag_value, expected_model):
    fake_client = FakeFlagClient({"agent-v2-experimental": flag_value})
    router = CapabilityRouter(ld_client=fake_client)
    ctx = FlagContext(user_key="test-user", session_id="s1", environment="test")
    bundle = router.resolve(ctx)
    assert bundle.model == expected_model

def test_kill_switch_overrides_flag():
    """Global kill switch must disable experimental bundle even when flag is on."""
    fake_client = FakeFlagClient({
        "agent-v2-experimental": True,
        "kill-switch-all-experiments": True,  # kill switch active
    })
    router = CapabilityRouter(ld_client=fake_client)
    ctx = FlagContext(user_key="test-user", session_id="s1", environment="test")
    bundle = router.resolve(ctx)
    assert bundle.model == "gpt-4o-2024-05-13"  # fell back to stable
